@using sv_1292ca867f354940ac2d0e5724fb5bff.Models

<h4 class="mb-3">References</h4>

@if (!string.IsNullOrEmpty(Error))
{
    <div class="alert alert-danger">@Error</div>
}

@for (int i = 0; i < References.Count; i++)
{
    var index = i;
    <ReferenceForm Reference="@References[index]"
                   Index="index"
                   CanRemove="@(References.Count > 1)"
                   OnChanged="r => UpdateReference(index, r)"
                   OnRemove="() => RemoveReference(index)" />
}

@if (References.Count < 3)
{
    <button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddReference">
        + Add Reference
    </button>
}

<div class="d-flex justify-content-between mt-4">
    <button class="btn btn-secondary" @onclick="OnBack">Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    [Parameter, EditorRequired] public List<Reference> References { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback<List<Reference>> OnReferencesChanged { get; set; }
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private string? Error;

    private void UpdateReference(int index, Reference updated)
    {
        var list = new List<Reference>(References) { [index] = updated };
        OnReferencesChanged.InvokeAsync(list);
    }

    private void RemoveReference(int index)
    {
        var list = new List<Reference>(References);
        list.RemoveAt(index);
        OnReferencesChanged.InvokeAsync(list);
    }

    private void AddReference()
    {
        if (References.Count >= 3) return;
        var list = new List<Reference>(References)
        {
            new(string.Empty, string.Empty, string.Empty, string.Empty)
        };
        OnReferencesChanged.InvokeAsync(list);
    }

    private async Task HandleNext()
    {
        Error = null;
        if (References.Count < 2)
        {
            Error = "Please provide at least 2 references.";
            return;
        }
        foreach (var r in References)
        {
            if (string.IsNullOrWhiteSpace(r.Name) || string.IsNullOrWhiteSpace(r.Relationship) ||
                string.IsNullOrWhiteSpace(r.Email) || string.IsNullOrWhiteSpace(r.Phone))
            {
                Error = "All fields are required for each reference.";
                return;
            }
        }
        await OnNext.InvokeAsync();
    }
}

